    font-size: 1rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.product-price {
    margin: 0;
    font-weight: 600;
    font-size: 1.1rem;
    color: #198754;
}

.product-rating {
    color: #ffc107;
    font-size: 1rem;
    letter-spacing: 1px;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: #fff;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    align-self: flex-start;
}

.btn-add-to-cart {
    margin-top: auto;
    padding: 0.45rem 0.75rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
    width: 100%;
}

.btn-add-to-cart:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-add-to-cart:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}
"}

