namespace sv_6a85ba2614604df4b6db2cf0fd8919fb.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_6a85ba2614604df4b6db2cf0fd8919fb.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

<div class="catalog-layout">
    <!-- Left Sidebar: Filters -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Category</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
            else
            {
                <p class="loading-text">Loading categories…</p>
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <label>
                    Min
                    <input type="number" min="0" step="0.01" @bind="minPrice" placeholder="Min" />
                </label>
                <label>
                    Max
                    <input type="number" min="0" step="0.01" @bind="maxPrice" placeholder="Max" />
                </label>
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <section class="catalog-main">
        <!-- Toolbar -->
        <div class="catalog-toolbar">
            <div class="sort-control">
                <label for="sort-select">Sort by:</label>
                <select id="sort-select" @onchange="OnSortChanged">
                    <option value="price_asc" selected="@(sortBy == "price_asc")">Price: Low to High</option>
                    <option value="price_desc" selected="@(sortBy == "price_desc")">Price: High to Low</option>
                    <option value="name_asc" selected="@(sortBy == "name_asc")">Name: A–Z</option>
                    <option value="rating_desc" selected="@(sortBy == "rating_desc")">Rating: Highest</option>
                </select>
            </div>
            <div class="results-summary">
                @if (result is not null && result.TotalCount > 0)
                {
                    var first = (result.Page - 1) * result.PageSize + 1;
                    var last = Math.Min(result.Page * result.PageSize, result.TotalCount);
                    <span>Showing @first–@last of @result.TotalCount products</span>
                }
            </div>
        </div>

        <!-- Content States -->
        @if (isLoading)
        {
            <div class="catalog-status">
                <p>Loading products…</p>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="catalog-status catalog-error">
                <p>@errorMessage</p>
                <button class="btn btn-primary" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="catalog-status">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <!-- Product Grid -->
            <div class="product-grid">
                @foreach (var product in result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="OnProductSelected"
                                 OnAddToCart="OnAddToCart" />
                }
            </div>

            <!-- Pagination -->
            <nav class="pagination" aria-label="Product pagination">
                <button class="btn btn-page"
                        disabled="@(currentPage <= 1)"
                        @onclick="() => GoToPage(currentPage - 1)">
                    Previous
                </button>

                @for (var i = 1; i <= totalPages; i++)
                {
                    var pageNum = i;
                    <button class="btn btn-page @(pageNum == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }

                <button class="btn btn-page"
                        disabled="@(currentPage >= totalPages)"
                        @onclick="() => GoToPage(currentPage + 1)">
                    Next
                </button>
            </nav>
        }
    </section>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int totalPages => result is not null && result.PageSize > 0
        ? (int)Math.Ceiling((double)result.TotalCount / result.PageSize)
        : 1;

    protected override async Task OnInitializedAsync()
    {
        var categoriesTask = LoadCategoriesAsync();
        var productsTask = SearchProductsAsync();
        await Task.WhenAll(categoriesTask, productsTask);
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = new List<string>();
        }
    }

    private async Task SearchProductsAsync()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
            result = null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await SearchProductsAsync();
    }

    private async Task RetryLoad()
    {
        await SearchProductsAsync();
    }

    private void OnProductSelected(Product product)
    {
        // Parent layout or NavigationManager can handle navigation to detail page.
        // This is a top-level page, so we'd typically navigate directly:
        // NavigationManager.NavigateTo($"/product/{product.Id}");
    }

    private void OnAddToCart(Product product)
    {
        // Hook for cart integration
    }
}

