toolArgs.file_text:
.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
    align-self: flex-start;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

/* Filters */
.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin: 0 0 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    gap: 0.5rem;
}

.price-inputs label {
    flex: 1;
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
}

.price-inputs input {
    width: 100%;
    padding: 0.35rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

/* Buttons */
.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background: #0d6efd;
    color: #fff;
}

.btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-secondary {
    background: #6c757d;
    color: #fff;
}

.btn-secondary:hover:not(:disabled) {
    background: #5c636a;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
}

.results-summary {
    color: #6c757d;
    font-size: 0.9rem;
}

/* Status */
.catalog-status {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.catalog-error {
    color: #dc3545;
}

/* Product Grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

/* Pagination */
.pagination {
    display: flex;
    justify-content: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.btn-page {
    background: #fff;
    border: 1px solid #dee2e6;
    padding: 0.4rem 0.75rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-page:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

